package main

import (
	"fmt"
	"log"
	"net/http"
	"strings"

	"github.com/gorilla/sessions"
)

type Comment struct {
	ID    string
	Text  string
	Author string
}

func renderComment(comment *Comment) (string, error) {
	return fmt.Sprintf("<p><strong>%s</strong> - %s</p>", comment.Author, escapeHTML(comment.Text)), nil
}

func escapeHTML(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	return s
}

var comments = []*Comment{
	&Comment{ID: "1", Text: "Hello, <b>world!</b>", Author: "John"},
	&Comment{ID: "2", Text: "This is a <i>test</i>.", Author: "Jane"},
}

func commentHandler(w http.ResponseWriter, r *http.Request) {
	session := sessions.GetSession(r)
	if session != nil && session.Values["username"] != nil {
		username := session.Values["username"].(string)

		template := `
			<html>
				<head>
					<title>Comments</title>
				</head>
				<body>
					<h1>Comments</h1>
					<ul>
						{{ range $comment := .comments }}
							<li>{{ renderComment $comment }}</li>
						{{ end }}
					</ul>
				</body>
			</html>
		`

		templateData := struct {
			comments []*Comment
		}{
			comments: comments,
		}

		err := template.Execute(w, templateData)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
	} else {
		http.Redirect(w, r, "/login", http.StatusFound)
	}
}

func main() {
	http.HandleFunc("/comments", commentHandler)

	log.Fatal(http.ListenAndServe(":8080", nil))
}